INSERT INTO public.photos VALUES (21472, 'Calle de Alfonso I, 1913', 'Imagen de la calle de Alfonso I desde el Coso alto, cuyo ingreso aparece flanqueado a la izquierda por el cafâ”œÂ® Moderno y a la derecha por la joyerâ”œÂ¡a El Trust.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65317000, -0.88211400, '0101000020E6100000F3FFAA23473AECBF3A5D16139BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53587004457.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53587004457.webp', 'https://www.flickr.com/photos/zaragozaantigua/53587004457/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21479, 'P.â”¬â•‘ de la Independencia 1923', 'Apenas tres meses de "Dictadura con Rey", de "Orden, trabajo y economâ”œÂ¡a", y oficialmente todo son sonrisas. Tambiâ”œÂ®n en esta invernal visita a Zaragoza, acompaâ”œâ–’ado el monarca de la reina, y los generales Sanjurjo, y Primo de Rivera. Recorrido y lugares visitados desde la llegada de Barcelona a la estaciâ”œâ”‚n Campo Sepulcro: paseo Mâ”¬Â¬ Agustâ”œÂ¡n, paseo de Pamplona, Facultades de Medicina y Ciencias, paseo de la Independencia, plaza de la Constituciâ”œâ”‚n, Coso, calle Alfonso I, metropolitano del Pilar, paseo por el paseo de la Independencia (momento que captura la imagen) hasta la Capitanâ”œÂ¡a General. Visita a la Diputaciâ”œâ”‚n Provincial, a la Lonja, al Campo de Maniobras Alfonso XIII, al Hospicio, a la Caridad, al Teatro Principal, al Cuartel del Cid, y desde nuevamente la estaciâ”œâ”‚n Campo Sepulcro, partida en direcciâ”œâ”‚n Madrid. Fin de visita. Y todo, sin perder la compostura, la impostura. Acaso, la claridad y definiciâ”œâ”‚n real de la instantâ”œÃ­nea. El germâ”œÃ­nico "pickelhaube" tras su majestad, deslumbra naturalmente entre deslumbrantes sonrisas de cartâ”œâ”‚n piedra. Fuente visual: Julio Requejo (AHPZ-DARA)', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65103800, -0.88201700, '0101000020E6100000568330B77B39ECBF043A933655D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14936020770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14936020770.webp', 'https://www.flickr.com/photos/zaragozaantigua/14936020770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21512, 'Quiosco de la Mâ”œâ•‘sica 1925', 'Paseo de la Independencia, con el Quiosco de la Mâ”œâ•‘sica en su centro. Provenâ”œÂ¡a de la plaza de Castelar, a donde volverâ”œÂ¡a en 1928. Fuente: Zaragoza 1908-2008. FCC.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65101000, -0.88202100, '0101000020E6100000B153AC1A8439ECBF3AAFB14B54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15711491352.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15711491352.webp', 'https://www.flickr.com/photos/zaragozaantigua/15711491352/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
