INSERT INTO public.photos VALUES (21573, 'P.â”¬â•‘ de la Independencia 1926', 'El aviador Ramâ”œâ”‚n Franco, hermano del que despuâ”œÂ®s fuera dictador, realizâ”œâ”‚ un vuelo transoceâ”œÃ­nico en 1926 en el hidroaviâ”œâ”‚n Plus Ultra, que le convirtiâ”œâ”‚ en una figura popular. En la foto, manifestaciâ”œâ”‚n patriâ”œâ”‚tica celebrando la hazaâ”œâ–’a, en el paseo de la Independencia de Zaragoza, con la plaza de la Constituciâ”œâ”‚n al fondo. Fuente visual: "Trabajo, sociedad, cultura. Una mirada al siglo XX en Aragâ”œâ”‚n", UGT, 2000.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65101200, -0.88222200, '0101000020E61000008BF9B9A1293BECBFDBA6785C54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24183625396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24183625396.webp', 'https://www.flickr.com/photos/zaragozaantigua/24183625396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21585, 'P.â”¬â•‘ de la Independencia c.1920', 'Vista del interior de los porches del paseo de la Independencia, desde la calle del Cinco de Marzo. Al fondo, la plaza de la Constituciâ”œâ”‚n. Fuente: Foto Jesâ”œâ•‘s Cormâ”œÃ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65151700, -0.88188900, '0101000020E6100000F777B6476F38ECBFDEE4B7E864D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24619791570.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24619791570.webp', 'https://www.flickr.com/photos/zaragozaantigua/24619791570/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21648, 'Pl. de Miguel Salamero 1923', 'Imagen capturada en los jardines de la plaza de Miguel Salamero (antigua de Santa Fe) en el angular espacio que a la derecha conservaba algunos antiguos inmuebles esquineros entre las antiguas calles de la Morerâ”œÂ¡a Cerrada (desde 1923 del Teniente Coronel Valenzuela) y del Baâ”œâ–’o (desde 1923 de la Morerâ”œÂ¡a, a secas). El de la imagen se corresponde con el edificio del nâ”¬â•‘ 9 de la calle de la Morerâ”œÂ¡a. A la derecha de â”œÂ®l y fuera de plano perduraba la casa que desde 1736 y hasta 1757 acogiâ”œâ”‚ a la familia paterna de Francisco Goya Lucientes. Todos ellos serâ”œÂ¡an derribados a principios de los aâ”œâ–’os 40. Al frente de la imagen, fachada del colegio de las MM. escolapias con el original aspecto neo-medieval dado en 1915 por el arquitecto Miguel â”œÃ¼ngel Navarro Pâ”œÂ®rez, luego bastante modificado a finales de los aâ”œâ–’os 40. Hacia la izquierda, la calle del Azoque.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65263300, -0.88360500, '0101000020E610000066A032FE7D46ECBF2BA5677A89D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51370350442.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51370350442.webp', 'https://www.flickr.com/photos/zaragozaantigua/51370350442/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21669, 'Calle de Alfonso I c.1932', 'Vista de la rectilâ”œÂ¡nea calle de Alfonso I tomada desde su arranque en el Coso Alto. Junto al vehâ”œÂ¡culo aparcado, los grandes Almacenes El â”œÃ¼guila, emblemâ”œÃ­ticos del carâ”œÃ­cter comercial de esta calle desde su apertura en 1865. El entorno se poblâ”œâ”‚ de familias adineradas. Al fondo, la recoleta plaza del Pilar, con la vista de la gran câ”œâ•‘pula central del templo.', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.65321800, -0.88223200, '0101000020E61000006F826F9A3E3BECBF4B94BDA59CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14725820468.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14725820468.webp', 'https://www.flickr.com/photos/zaragozaantigua/14725820468/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22580, 'Julio Cejador Frauca 1977', 'Imagen de la calle Julio Cejador Frauca (antiguo Camino Viejo de Cuarte) en su primer tramo, donde arranca del Paseo de Ruiseâ”œâ–’ores (al fondo). El muro de la derecha servâ”œÂ¡a tanto para delimitar a la Fâ”œÃ­brica de Harinas "La Imperial", como a salvar el importante desnivel entre esta calle, y el paseo del Canal, situado una terraza mâ”œÃ­s arriba. A la izquierda, muro que delimita los hotelitos vecinos del Colegio Pompiliano (al fondo, a la izquierda). Fuente visual: "La evoluciâ”œâ”‚n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.63526700, -0.89123300, '0101000020E610000003B68311FB84ECBF309DD66D50D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15565558869.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15565558869.webp', 'https://www.flickr.com/photos/zaragozaantigua/15565558869/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21715, 'Coso Alto 1936', 'La llegada de algâ”œâ•‘n contingente de tropa (voluntaria o regular) a la ciudad se convertâ”œÂ¡a en una "espontâ”œÃ­nea" muestra de adhesiâ”œâ”‚n popular al "Movimiento" nacionalista. En este caso, estamos en el Coso Alto, con el fondo escâ”œÂ®nico de los nâ”œâ•‘meros pares, desde la plaza de la Constituciâ”œâ”‚n (luego, de Espaâ”œâ–’a), y el arco de San Roque. Este era el arco de mayor trâ”œÃ­fico humano de la ciudad, antiguo lugar de paso para la circulaciâ”œâ”‚n de personas y mercancâ”œÂ¡as entre el Coso y la "Morerâ”œÂ¡a", por la plazuela de San Roque, la calle de Palomeque, la plazuela de Santâ”œÃ­ngel, y la calle del Azoque. Este arco que aparece en la imagen fue remozado no hacâ”œÂ¡a muchos aâ”œâ–’os, para darle una apariencia mâ”œÃ­s "medieval", aunque nunca pretendiâ”œâ”‚ ser mâ”œÃ­s que un funcional paso cubierto con viviendas en su parte superior. Serâ”œÃ­ derribado en 1942 para ensanche al trâ”œÃ­fico rodado, lo que supondrâ”œÃ­ el derribo de buena parte de lo que en la imagen aparece. Un tranvâ”œÂ¡a de la lâ”œÂ¡nea 7, posiblemente el nâ”œâ•‘mero 41, aguarda pacientemente para seguir su recorrido desde la plaza de la Constituciâ”œâ”‚n hasta el Portillo. Fuente: Foto Lozano, Archivo Campos, "La guerra civil en Aragâ”œâ”‚n", ed. Delsan, 2010', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65321000, -0.88286500, '0101000020E6100000AA0EB9196E40ECBFC8B5A1629CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19407328325.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19407328325.webp', 'https://www.flickr.com/photos/zaragozaantigua/19407328325/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21762, 'Coso Alto 1930', 'Coso Alto desde un balcâ”œâ”‚n del antiguo palacio del Conde de Fuentes, junto al Banco de Aragâ”œâ”‚n. Al fondo, la plaza de la Constituciâ”œâ”‚n. Fuente visual: Foto Conrado Barlâ”œÂ®s, donada por Daniel Barlâ”œÂ®s y digitalizada por Josâ”œÂ® Luis Cintora para www.rafaelcastillejo.com', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65309200, -0.88215500, '0101000020E61000009817601F9D3AECBFBEA3C68498D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22619780504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22619780504.webp', 'https://www.flickr.com/photos/zaragozaantigua/22619780504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
