INSERT INTO public.photos VALUES (21771, 'Coso Alto 1930', 'Desde las alturas del Casino Mercantil, imagen del Coso Alto. Al fondo, la iglesia parroquial de Santiago el Mayor. Mâ”œÃ­s lejos aâ”œâ•‘n, la Casa-Hospicio, antigua Real Casa de Misericordia. Fuente visual: Foto Conrado Barlâ”œÂ®s, donada por Daniel Barlâ”œÂ®s y digitalizada por Josâ”œÂ® Luis Cintora para www.rafaelcastillejo.com', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65318500, -0.88243700, '0101000020E6100000A5F8F884EC3CECBF6F9EEA909BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22854404727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22854404727.webp', 'https://www.flickr.com/photos/zaragozaantigua/22854404727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21809, 'Calle de Alfonso I c.1933', 'Imagen de calle Alfonso I en los comienzos de la dâ”œÂ®cada de los aâ”œâ–’os 30, comercializada como postal por la editorial Arribas, y circulada en 1939. Se trata de una ya clâ”œÃ­sica mirada a esta calle, desde la altura de la original sede del Banco de Aragâ”œâ”‚n, en la intersecciâ”œâ”‚n del Coso alto con esta decimonâ”œâ”‚nica calle. Fuente visual: www.delcampe.net/', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65309200, -0.88215500, '0101000020E61000009817601F9D3AECBFBEA3C68498D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28765808751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28765808751.webp', 'https://www.flickr.com/photos/zaragozaantigua/28765808751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21834, 'Paseo Independencia 1933', 'La Guardia de Asalto cachea a un viandante en el paseo de la Independencia, ante el nâ”œâ•‘mero 8. Allâ”œÂ¡ se aloja el Cafâ”œÂ® Central, antes Matossi. Este establecimiento habâ”œÂ¡a sido el Gran Cafâ”œÂ® Suizo y luego fue el Cafâ”œÂ® Alaska. A la derecha, fuera de plano, la calle del Cinco de Marzo. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65099400, -0.88247000, '0101000020E6100000936FB6B9313DECBF34F279C553D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33492591446.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33492591446.webp', 'https://www.flickr.com/photos/zaragozaantigua/33492591446/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21840, 'Calle de Alfonso I 1931', 'Imagen capturada en el Coso Alto y centrada en el arranque de la moderna calle de Alfonso I, vertebrada intencionalmente como acceso directo a la plaza del Pilar, al fondo, y como escaparate comercial y residencial privilegiado de las clases altas zaragozanas. Tras el fotâ”œâ”‚grafo, fuera de plano, tendido tranviario de la lâ”œÂ¡nea de Circunvalaciâ”œâ”‚n y de la lâ”œÂ¡nea del Ayuntamiento. Fuente visual: foto Josep Maria Co i de Triola, en Arxiu Fotogrâ”œÃ¡fic del Centre Excursionista de Catalunya.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65315100, -0.88207300, '0101000020E61000004FE8F527F139ECBFC32CB4739AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35059360486.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35059360486.webp', 'https://www.flickr.com/photos/zaragozaantigua/35059360486/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21849, 'P.â”¬â•‘ Independencia 1934', 'Imagen de la fachada del moderno y novâ”œÂ¡simo Cafâ”œÂ® Alaska, resultado de la profunda reforma acometida con diseâ”œâ–’o de los hermanos Borobio en el preexistente Cafâ”œÂ® Central. El resultado, apabullante para la Zaragoza del momento, despertâ”œâ”‚ inusitada expectaciâ”œâ”‚n y energâ”œÂ®ticos comentarios a favor. En la imagen, la abundante parroquia congregada en la inauguraciâ”œâ”‚n deja amablemente espacio para que la captura fotogrâ”œÃ­fica luzca despejada y caballera. Al fondo, a la derecha, la calle del Cinco de Marzo desemboca en el paseo. Fuente visual original: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65142400, -0.88205900, '0101000020E6100000118FC4CBD339ECBF2DEA93DC61D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35697653373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35697653373.webp', 'https://www.flickr.com/photos/zaragozaantigua/35697653373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21852, 'Calle de Valenzuela 1934', 'Imagen con la imponente fachada, tras reciente reforma, del Hotel Lafuente sito desde los aâ”œâ–’os veinte en la antigua calle de la Morerâ”œÂ¡a Cerrada nâ”¬â•‘ 3, luego redenominada de Valenzuela. La captura desde cierta altura posiblemente se ha realizado desde el desaparecido edificio esquinero cuyas traseras recaâ”œÂ¡an en la plaza de Salamero (antigua de Santa Fe), inmueble en el que viviâ”œâ”‚ la familia paterna del joven Francisco Goya desde 1736 hasta 1757, y que desde 1928 tenâ”œÂ¡a una placa conmemorativa. A la izquierda, vista parcial del antiguo nâ”¬â•‘ 1 de la estrecha calle de Valenzuela, que arrancaba en la irregular y angulosa plaza de San Roque, que fuera antigua plazuela de San Camilo o de la Manterâ”œÂ¡a, entre el Arco de San Roque, el colegio de Santo Tomâ”œÃ­s de Villanueva (luego colegio de las MM. Escolapias), el convento de los PP. Agonizantes y la casa de los condes de Fuentes. Aâ”œâ–’os despuâ”œÂ®s, este entorno serâ”œÂ¡a radicalmente reurbanizado, perdurando el hotel. Transitoriamente. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65269900, -0.88310000, '0101000020E61000008A1F63EE5A42ECBFE2900DA48BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35795712264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35795712264.webp', 'https://www.flickr.com/photos/zaragozaantigua/35795712264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21872, 'Coso Alto c.1935', 'Imagen capturada en altura desde uno de los balcones de la casa del siglo XVI del conde de Sâ”œÃ­stago, centrada en el tramo alto del Coso y el emboque a la calle de Alfonso I. Al fondo, el edificio de las Escuelas Pâ”œÂ¡as. Por una de las dos vâ”œÂ¡as tranviarias traquetea hacia la terminal de la plaza de la Constituciâ”œâ”‚n la unidad 40 de la lâ”œÂ¡nea 7 Ayuntamiento-Portillo. Fuente visual: Archivo Arribas, AMZ.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65315100, -0.88207300, '0101000020E61000004FE8F527F139ECBFC32CB4739AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38228750422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38228750422.webp', 'https://www.flickr.com/photos/zaragozaantigua/38228750422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21890, 'Coso Alto 1939', 'Imagen capturada bajo el Arco de San Roque y centrada en el paso de una procesiâ”œâ”‚n el dâ”œÂ¡a del Corpus por el Coso Alto y encaminada hacia la plaza de Espaâ”œâ–’a. Entre le pâ”œâ•‘blico destaca un alto nâ”œâ•‘mero de tropa militar. Al fondo, fachada del Coso correspondiente a los nâ”œâ•‘meros 13, con el Hotel Oriente y la perfumerâ”œÂ¡a de Jenaro Lafita, y el nâ”¬â•‘ 15, sede de la Central Obrera Nacionalsindicalista que editaba desde 1936 "Obrerismo. Semanario pro justicia social", â”œâ”‚rgano de los sindicatos obreros nacional-sindicalistas. Ademâ”œÃ­s, y en local comercial, los almacenes de Gaspar Crespo de material de escritorio, papelerâ”œÂ¡a, y aparatos de precisiâ”œâ”‚n.', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.65322600, -0.88262900, '0101000020E6100000B309302C7F3EECBFCD72D9E89CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49901768962.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49901768962.webp', 'https://www.flickr.com/photos/zaragozaantigua/49901768962/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21907, 'Plaza de Salamero c.1934', 'Interesantâ”œÂ¡sima e inâ”œÂ®dita imagen capturada a la sombra de los arbolados jardines de la plaza de Salamero (antigua de Santa Fe) y a espaldas del monumento a Joaquâ”œÂ¡n Dicenta ubicado en el centro de este espacio desde 1928 y desplazado tras el 18 de julio de 1936 al Parque de Primo de Rivera por presiones de Falange. El objetivo se centra en la zona suroccidental de la plaza, con el telâ”œâ”‚n de fondo edilicio de la calle del Azoque entre los nâ”œâ•‘meros 80 y 90. En el centro se abre la calle de la Biblioteca, que conduce al Hospital Militar y a la iglesia parroquial de Santiago, que daba nombre al homâ”œâ”‚nimo barrio que aquâ”œÂ¡ llegaba desde la calle del Caballo. En los bajos comerciales de este tramo de la calle del Azoque, vista de la carbonerâ”œÂ¡a de Pedro Soriano, el establecimiento de ultramarinos de Modesto Condor, y la carnicerâ”œÂ¡a de Pedro Peribâ”œÃ­â”œâ–’ez. Antes y ubicado en la plaza, un "fruit stand" (puesto de frutas) ambulante llama la atenciâ”œâ”‚n del fotâ”œâ”‚grafo.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65229600, -0.88423800, '0101000020E6100000A12C7C7DAD4BECBFE3A7716F7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51740621980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51740621980.webp', 'https://www.flickr.com/photos/zaragozaantigua/51740621980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21948, 'Paseo Independencia c.1949', 'La Instituciâ”œâ”‚n Teresiana, una deriva de la Instituciâ”œâ”‚n Catâ”œâ”‚lica de Enseâ”œâ–’anza, abriâ”œâ”‚ en 1932 una residencia universitaria para chicas en la Calle del Temple nâ”¬â•‘ 20, y como sus balcones daban a la calle Sta. Isabel, ese fue el nombre con que se quedâ”œâ”‚. Tras el fallido golpe de estado de julio de 1936 contra la Repâ”œâ•‘blica, y hasta 1939, permaneciâ”œâ”‚ cerrada. En 1944 el nuevo Ministerio de Educaciâ”œâ”‚n concede a la Instituciâ”œâ”‚n Teresiana la direcciâ”œâ”‚n y gestiâ”œâ”‚n del CMUF Santa Isabel, en su nueva ubicaciâ”œâ”‚n del Paseo de la Independencia nâ”¬â•‘ 10. En 1951 se trasladâ”œâ”‚ a unas instalaciones mâ”œÃ­s amplias en el redenominado paseo de Fernando El Catâ”œâ”‚lico nâ”¬â•‘ 2, y en el curso 1972-1973 inaugurâ”œâ”‚ el vigente edificio de la Ciudad Universitaria, con espacio para casi 200 internas. Desde octubre de 1990 depende directamente de la Universidad pâ”œâ•‘blica de Zaragoza, con lo que pasâ”œâ”‚ de ser un colegio exclusivamente femenino, a mixto. En la imagen, el CMUF Sta. Isabel en su ubicaciâ”œâ”‚n del paseo de la Independencia nâ”¬â•‘ 10, en uno de esos historicistas edificios que pretendâ”œÂ¡an reflejar la rue de Rivoli en Zaragoza, pero que terminâ”œâ”‚ piqueteado para crecer en verticalidad, modernidad, y bancarismo. Fuente: cmusantaisabel.unizar.es/', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65106000, -0.88239400, '0101000020E6100000D3F88557923CECBFECDD1FEF55D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16783290750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16783290750.webp', 'https://www.flickr.com/photos/zaragozaantigua/16783290750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22012, 'Calle de Alfonso I c.1945', 'Canicular imagen de la decimonâ”œâ”‚nica calle de Alfonso I capturada desde la altura de la original sede del Banco de Aragâ”œâ”‚n en el nâ”¬â•‘ 42 del Coso. A la izquierda, el veterano cafâ”œÂ® Moderno poco antes de su cierre, ubicado desde principios de siglo en los bajos del nâ”¬â•‘ 17 del Coso angular con el nâ”¬â•‘ 1 de Alfonso I, y a continuaciâ”œâ”‚n los referenciales almacenes El â”œÃ¼guila. Al fondo, la câ”œâ•‘pula central del metropolitano templo del Pilar. Fuente visual: ediciones Garcâ”œÂ¡a Garrabella, en www.delcampe.es', 1945, 1945, 1945, 'Anos 40', 'CENTRO', 41.65305500, -0.88215700, '0101000020E6100000C5FF1D51A13AECBFA1BE654E97D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42576582714.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42576582714.webp', 'https://www.flickr.com/photos/zaragozaantigua/42576582714/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22058, 'Banco de Aragâ”œâ”‚n 1951', '1951. Edificio del Banco de Aragâ”œâ”‚n, en Coso nâ”œâ•‘m. 42, proyectado en 1913 e inaugurado en 1917 segâ”œâ•‘n diseâ”œâ–’o del arquitecto Manuel del Busto. Fue segunda sede central de la entidad en Zaragoza, entre 1917 y 1951. Fuente: Recuerdo de la inauguraciâ”œâ”‚n del nuevo edificio del Banco de Aragâ”œâ”‚n en Zaragoza, 1951.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65288900, -0.88206500, '0101000020E61000009947FE60E039ECBF8675E3DD91D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14925082941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14925082941.webp', 'https://www.flickr.com/photos/zaragozaantigua/14925082941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22092, 'Banco de Aragâ”œâ”‚n 1951', 'Edificio del Banco de Aragâ”œâ”‚n inaugurado en 1951, en el Coso 36-40 de Zaragoza, esquina con la del Teniente Coronel Valenzuela, segâ”œâ•‘n proyecto de Juliâ”œÃ­n Laguna. El solar habâ”œÂ¡a sido ocupado por el Palacio de los marqueses de Villasimpliz (s. XVI) y por el cine Ena Victoria (s. XX). Fue tercera y â”œâ•‘ltima sede de esa entidad, hasta ser absorbida por el Banco Central en 1970. Fuente: Recuerdo de la inauguraciâ”œâ”‚n del nuevo edificio del Banco de Aragâ”œâ”‚n en Zaragoza, 1951.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65322500, -0.88264000, '0101000020E6100000AD86C43D963EECBFFDF675E09CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19443981149.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19443981149.webp', 'https://www.flickr.com/photos/zaragozaantigua/19443981149/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22125, 'Calle de Alfonso I c.1950', 'Hogar Moderno, establecimiento comercial situado en el nâ”¬â•‘ 6 de la calle de Alfonso I desde el aâ”œâ–’o 1920, dedicado a la venta de vajilla y menaje domâ”œÂ®stico que fue cerrado en 2014. Un vehâ”œÂ¡culo permanece estacionado junto a la acera de los impares. Al fondo, el Coso Alto y el antiguo edificio del Banco de Aragâ”œâ”‚n. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.65324100, -0.88194300, '0101000020E6100000C3F4BD86E038ECBF03B4AD669DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22779028039.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22779028039.webp', 'https://www.flickr.com/photos/zaragozaantigua/22779028039/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22140, 'Restaurante Savoy c.1950', 'Fotografâ”œÂ¡a publicitaria del Restaurante Savoy, ubicado hasta 2004 en el antiguo edificio del Banco de Aragâ”œâ”‚n del Coso 42, frente a la calle de Alfonso I. Fuente: www.todocoleccion.net', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.65300800, -0.88217900, '0101000020E6100000BAF94674CF3AECBF600322C495D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24899772806.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24899772806.webp', 'https://www.flickr.com/photos/zaragozaantigua/24899772806/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22146, 'Cine Rex 1953', 'Imagen capturada durante la construcciâ”œâ”‚n del nuevo cinematâ”œâ”‚grafo Rex proyectado por los arquitectos Josâ”œÂ® de Yarza Garcâ”œÂ¡a y Teodoro Râ”œÂ¡os Usâ”œâ”‚n como parte integrante de un gran complejo que incluâ”œÂ¡a un hotel, dos salas de cine, un pasaje comercial y viviendas entre el paseo de la Independencia y la calle del Requetâ”œÂ® Aragonâ”œÂ®s. El Rex era el segundo cine en tamaâ”œâ–’o de este proyecto, compartiendo medianera con el cine Palafox o cine principal (a la izquierda de la imagen). Serâ”œÂ¡a inaugurado en 1954. Al fondo, el colegio de Santa Rosa de la Orden de Predicadores y la medianera con el nâ”¬â•‘ 7 de la calle del Requetâ”œÂ® Aragonâ”œÂ®s. Fuente visual: arch. J. de Yarza', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65157700, -0.88302400, '0101000020E6100000CAA8328CBB41ECBFB4E908E066D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26317818299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26317818299.webp', 'https://www.flickr.com/photos/zaragozaantigua/26317818299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22311, 'Coso Alto 1969', 'Tramo del Coso alto entre la calle del Teniente Coronel Valenzuela (a la derecha) y la plaza de Espaâ”œâ–’a (al fondo). En el cine Coso se proyecta el filme "Cerveza para todos" (Frank Tashlin, 1968). Fuente visual: Foto Kolor - Zerkowitz, Barcelona, 1969; Postal colecciâ”œâ”‚n Miguel Pascual Laborda. www.facebook.com/photo.php?fbid=407008862797117&set=p...', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.65322500, -0.88237200, '0101000020E6100000DFFE5C34643CECBFFDF675E09CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15718787768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15718787768.webp', 'https://www.flickr.com/photos/zaragozaantigua/15718787768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22314, 'Blasco Ijazo 1968', 'Archivo Municipal. Gerardo Sancho Ramo. Noviembre Junio 1968. Nacido cuando derribaron la Torre Nueva, muy pronto mostrâ”œâ”‚ inclinaciones periodâ”œÂ¡sticas, participando en publicaciones escolares dirigidas por Josâ”œÂ® Calvo Sotelo. Colaborâ”œâ”‚ con "El Noticiero" y con la "Hoja del Lunes", editada por la Asociaciâ”œâ”‚n de la Prensa, de la que fue presidente desde el 18 de julio de 1936, hasta 1968. El pleno municipal de 1954 le nombrâ”œâ”‚ cronista oficial de la ciudad reconociendo, como hombre de orden y del râ”œÂ®gimen, su divulgaciâ”œâ”‚n de aspectos de la historia zaragozana. Produjo muchas obras sobre Zaragoza: "Las calles de la ciudad y significado de sus nombres" (1944, actualizada en 1962); "Zaragoza y sus locales de espectâ”œÃ­culos. Los que fueron y los que son... 1764-1945" (1945), "Historia de la prensa zaragozana 1683-1947" (1947), y el sexteto "â”¬Ã­Aquâ”œÂ¡... Zaragoza!" (1948-1960). En la imagen, Blasco Ijazo gesticula en un homenaje de sus colegas periodistas al dejar la presidencia de la Asociaciâ”œâ”‚n de la Prensa de Aragâ”œâ”‚n, en la sede de la misma (calle Requetâ”œÂ® Aragonâ”œÂ®s, 9). Su discurso estâ”œÃ­ respaldado por un tridente letal para las fuerzas del mal: Franco, Josâ”œÂ® Antonio, y la virgen del Pilar. Serâ”œÃ­ sustituido por Antonio Bruned Mompeâ”œâ”‚n, el joven a la izquierda de la virgen.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65189500, -0.88332600, '0101000020E61000009D9B36E33444ECBF85B69C4B71D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15754697952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15754697952.webp', 'https://www.flickr.com/photos/zaragozaantigua/15754697952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22319, 'Paseo Independencia 1965', 'En primer plano, solar anunciado para la construcciâ”œâ”‚n del SEPU, en la esquina con la calle Requetâ”œÂ® Aragonâ”œÂ®s, inaugurado en 1969. Al fondo, la plaza de Espaâ”œâ–’a, con el Pilar detrâ”œÃ­s. Fuente: www.facebook.com/photo.php?fbid=765588400178578&set=o...', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65133300, -0.88191100, '0101000020E6100000EB71DF6A9D38ECBF1DE736E15ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15859257352.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15859257352.webp', 'https://www.flickr.com/photos/zaragozaantigua/15859257352/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22412, 'Requetâ”œÂ® Aragonâ”œÂ®s 1968', 'Imagen superproducida en el entorno del Hotel Goya, nâ”¬â•‘ 5 de la calle Requetâ”œÂ® Aragonâ”œÂ®s (antigua del Cinco de Marzo), horas antes del encuentro de fâ”œâ•‘tbol de 1â”¬Â¬ Divisiâ”œâ”‚n, correspondiente a la jornada 22 de la Liga, entre los equipos Real Zaragoza C.D., y la U.D. Las Palmas. Dos peloteros foranos (posiblemente, Martâ”œÂ¡n Marrero, y Gilberto) posan leyendo atentamente, en la vastedad del diario mâ”œÃ­s antiguo de la regiâ”œâ”‚n aragonesa, las â”œâ•‘ltimas noticias difundidas por la prensa libre sobre los tremendos combates en la Ciudadela de Huâ”œÂ® (Vietnam), como escenario bâ”œÂ®lico destacado durante la comunista ofensiva del Tet. A su izquierda, Catherine Deneuve ilumina con su turbadora sonrisa desde la portada de la revista "Elle" donde anunciaba su prâ”œâ”‚xima pelâ”œÂ¡cula, "Manon 70", de temâ”œÃ­tica muy atrevidamente francesa, compartiendo pâ”œÃ­ginas con un adelanto de la maravillosa moda "prâ”œÂ¬t-â”œÃ¡-porter" que se lucirâ”œÂ¡a en la tranquila primavera de ese aâ”œâ–’o. Las preciosas postales expuestas, un catâ”œÃ­logo de diversos iconos turâ”œÂ¡sticos que incluyen vistas de la moderna Zaragoza, pertenecen a un quiosco incrustado entre el Hotel Goya y el Pasaje Palafox, con las ascendentes escaleras hacia el Cine Rex, despuâ”œÂ®s. En la otra acera, un cartel indicador orienta hacia el veterano establecimiento del "Jai-Alai" en su segunda etapa como frontâ”œâ”‚n de pelota, tras haber ejercido durante casi treinta aâ”œâ–’os como sala de proyecciones del Frontâ”œâ”‚n Cinema. Al fondo, la plaza de Salamero, antigua de Santa Fe. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65172100, -0.88263800, '0101000020E6100000809E060C923EECBFE78EFE976BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25053256141.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25053256141.webp', 'https://www.flickr.com/photos/zaragozaantigua/25053256141/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22417, 'Vista 1968', '"Vista desde el torreâ”œâ”‚n", tinta china y gouache sobre papel, Gonzalo de Diego, 1968. Con las torres del Banco de Aragâ”œâ”‚n y del Pilar al fondo, ofrece un caserâ”œÂ¡o en gran parte desaparecido, en el entorno de las plazas de Salamero y del Carmen. El torreâ”œâ”‚n al que alude el tâ”œÂ¡tulo es, quizâ”œÃ­s, el remate del edificio del paseo de Pamplona 1, esquinero con la calle del Doctor Cerrada. Fuente visual: zaragozacool.wordpress.com', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65149100, -0.88370200, '0101000020E6100000041DAD6A4947ECBFB5519D0E64D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26245096647.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26245096647.webp', 'https://www.flickr.com/photos/zaragozaantigua/26245096647/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22523, 'Calle de Alfonso I 1960', 'Fotograma de la pelâ”œÂ¡cula "Alerta en el cielo" rodada en Zaragoza en el otoâ”œâ–’o de 1960. Aquâ”œÂ¡ se muestra la "iluminaciâ”œâ”‚n artâ”œÂ¡stica" de la calle de Alfonso I incluida en el programa oficial de las fiestas del Pilar de ese aâ”œâ–’o. Esta tradicional moda de poner iluminaciâ”œâ”‚n extra a contadas y selectas calles de la ciudad en fechas tan seâ”œâ–’aladas comenzâ”œâ”‚ un par de aâ”œâ–’os antes, si bien en 1959 brillaron por su ausencia. Las de este aâ”œâ–’o eran consideradas menos "pueblerinas", si bien esta moda ni tenâ”œÂ¡a ese origen ni habâ”œÂ¡a pueblo que se las pudiera costear. En la imagen, emboque a la calle de Alfonso I desde el Coso.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65310600, -0.88201700, '0101000020E6100000568330B77B39ECBF236937FA98D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/55095008013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/55095008013.webp', 'https://www.flickr.com/photos/zaragozaantigua/55095008013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22620, 'Recogidas Pza. del Carmen 1978', 'Inicio del derribo del antiguo convento de las "Recogidas" que se extendâ”œÂ¡a entre la calle de Câ”œÃ­diz (a la izquierda) y la plaza del Carmen. La imagen ha sido capturada precisamente desde esta plaza, con detalle de los espacios conventuales que en 1964 habâ”œÂ¡an sido alquilados a varios establecimientos comerciales. Fuente: Gerardo Sancho Ramo, Archivo Pâ”œâ•‘blico Municipal.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.65098100, -0.88437700, '0101000020E6100000FAB48AFED04CECBFA0A86C5853D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19551809090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19551809090.webp', 'https://www.flickr.com/photos/zaragozaantigua/19551809090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22692, 'P.â”¬â•‘ de la Independencia 1970', 'Interesante, colorista, e insâ”œâ”‚lita imagen del paseo de la Independencia, como moderna vâ”œÂ¡a de alta capacidad para circulaciâ”œâ”‚n rodada, con tranvâ”œÂ¡as en los mâ”œÃ­rgenes. A la izquierda, el recientâ”œÂ¡simo y moderno edificio del gran centro comercial vertical "SEPU", y enfrente suyo, al otro lado del paseo, el solar sobre el que pronto se edificarâ”œÂ¡a su clon en forma de "Galerâ”œÂ¡as Preciados". A la izquierda extrema, inmediato, el solar sobre el que se levantarâ”œÃ­ el nuevo y no menos impactante nâ”¬â•‘ 22 del paseo, en tiempos en que esas cosas no importaban demasiado. Sobre la medianera del bloque del nâ”¬â•‘ 18, rastros del derribado edificio, de los tiempos de la antigua calle de la Independencia Esta captura fue realizada por la australiana Lindsay Bridge un luminoso dâ”œÂ¡a de junio de 1970, en su paso por la ciudad. Fuente visual: www.flickr.com/photos/intervene/4158456835/in/album-72157...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65115700, -0.88192200, '0101000020E6100000E5EE737CB438ECBFDEC7D11C59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27073290990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27073290990.webp', 'https://www.flickr.com/photos/zaragozaantigua/27073290990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22733, 'Plaza del Carmen 1973', 'Imagen de la antigua plaza del Carmen centrada en el caserâ”œâ”‚n del nâ”¬â•‘ 9, esquinero con la calle de la Vieja Guardia, donde destaca la gran estructura del bloque en construcciâ”œâ”‚n que, con el nâ”¬â•‘ 2, se levanta sobre parte del enorme cuartel del Carmen. El referido caserâ”œâ”‚n es renombrado, sobre todo, por albergar en sus bajos un bar de nombre insular. El edificio era una antigua construcciâ”œâ”‚n, posiblemente del siglo XVII, profundamente remodelada en el XVIII cuando su propietario fue Francisco Montemayor, y a finales de siglo fue de Pedro Cortâ”œÂ®s y Larraz, obispo de Guatemala, y luego de Tortosa. Unos aâ”œâ–’os despuâ”œÂ®s, fue derribado y homologado con su vecino del otro lado de la calle. Fuente visual: foto Gerardo Sancho Ramo AMZ', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65152900, -0.88420500, '0101000020E6100000B3B5BE48684BECBFA2B2614D65D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31167796974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31167796974.webp', 'https://www.flickr.com/photos/zaragozaantigua/31167796974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22773, 'Calle del Doctor Gâ”œâ”‚mez Ulla 1975', 'Imagen aâ”œÂ®rea de la calle del Doctor Gâ”œâ”‚mez Ulla y centrada en el tramo de los inmuebles, ya deshabitados y a la espera del derribo de los nâ”œâ•‘meros 3-7, y el solar del ya derribado inmueble del nâ”¬â•‘ 9, entre la calle del Azoque, a la izquierda, y la avenida Imperial, a la derecha. Esta calle estaba abocada a la desapariciâ”œâ”‚n al estar incluida en el Plan Parcial Especial de San Ildefonso, que afectâ”œâ”‚ al perâ”œÂ¡metro delimitado por la plaza de Santâ”œÃ­ngel, las calles de Pignatelli, Ramâ”œâ”‚n y Cajal, Capitâ”œÃ­n Portolâ”œÂ®s, Azoque, Teniente General Valenzuela, y Palomeque. El provisional muro de ladrillo de primer tâ”œÂ®rmino, convertido en provisional soporte publicitario, seâ”œâ–’ala el nuevo alineamiento recayente a la reformada plaza de Miguel Salamero, que aâ”œâ–’os mâ”œÃ­s tarde guardarâ”œÃ­n los nuevos edificios aquâ”œÂ¡ construidos, tras el derribo de los de la imagen. A la izquierda, los inmuebles de los nâ”œâ•‘meros 50-56 de la calle del Azoque. Al fondo y a la derecha, tras el gran solar se levanta el muro medianil del Teatro Fleta.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.65215200, -0.88451700, '0101000020E61000006A317898F64DECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33974070708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33974070708.webp', 'https://www.flickr.com/photos/zaragozaantigua/33974070708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22800, 'Calle del Dr. Gâ”œâ”‚mez Ulla 1975', 'Imagen, hasta ahora sin identificar, capturada en la calle del Doctor Gâ”œâ”‚mez Ulla y centrada en el tramo de los inmuebles, ya deshabitados y a la espera del derribo, de los nâ”œâ•‘meros 3-7, entre la calle del Azoque y la avenida Imperial, al fondo. Esta calle estaba abocada a la desapariciâ”œâ”‚n, tras el previo despeje del lado de los pares, a la derecha. El provisional muro de ladrillo de primer tâ”œÂ®rmino, con carteles promocionales del Circo Atlas, seâ”œâ–’ala el nuevo alineamiento recayente a la reformada plaza de Miguel Salamero, y el antiguo acceso a la calle es ahora un "paso cortado", como indica el râ”œâ”‚tulo bocarriba. Los modernos edificios de viviendas que aquâ”œÂ¡ se construyeron mâ”œÃ­s tarde tienen su ingreso por el nâ”¬â•‘ 30 de la avenida de Câ”œÂ®sar Augusto. Esta fue la antigua y recoleta calle de la Biblioteca, que conducâ”œÂ¡a hasta el Hospital Militar y la iglesia de San Ildefonso. Ninguno de los nuevos y abundantes viales abiertos en la ciudad desde entonces han tomado el relevo de estas dos denominaciones perdidas.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.65220000, -0.88451700, '0101000020E61000006A317898F64DECBFC139234A7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46727179095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46727179095.webp', 'https://www.flickr.com/photos/zaragozaantigua/46727179095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22801, 'Calle del Requetâ”œÂ® Aragonâ”œÂ®s 1973', 'Colorista imagen de la pista de hielo El Ibâ”œâ”‚n en una vista interior capturada desde la zona de ingreso por la calle del Requetâ”œÂ® Aragonâ”œÂ®s. En 1932 se inaugurâ”œâ”‚ el Frontâ”œâ”‚n Emendek en en la calle del Cinco de Marzo nâ”¬â•‘ 3-5, con proyecto del arquitecto Ignacio Mendizâ”œÃ­bal Lujambio. Desde 1934 y hasta los aâ”œâ–’os 50 fue reconvertido en el Frontâ”œâ”‚n Cinema, con 1.250 localidades, y luego albergarâ”œÂ¡a la sala de fiestas Râ”œÂ¡o Club. Desde 1963 fue otra vez frontâ”œâ”‚n, ahora denominado Jai Alai, hasta que en 1973 se instalâ”œâ”‚ una pista de hielo para la prâ”œÃ­ctica multitudinaria del patinaje desde una perspectiva lâ”œâ•‘dica, de vida breve.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65210400, -0.88286500, '0101000020E6100000AA0EB9196E40ECBF9FCBD42478D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47524131481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47524131481.webp', 'https://www.flickr.com/photos/zaragozaantigua/47524131481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23033, 'Calle de Alfonso I 1992', 'Nocturna imagen del arranque de la calle de Alfonso I capturada desde el tramo alto del Coso. En primer tâ”œÂ®rmino, barandillas reforzadas para evitar que los peatones estrangulen esta importante vâ”œÂ¡a para el trâ”œÃ­fico rodado. A la izquierda, el Banco de Fomento radicado en el antiguo inmueble de los Almacenes El â”œÃ¼guila. Al fondo, la câ”œâ•‘pula mayor del templo del Pilar.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65321800, -0.88198500, '0101000020E61000007E00529B3839ECBF4B94BDA59CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50207940452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50207940452.webp', 'https://www.flickr.com/photos/zaragozaantigua/50207940452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23071, 'P.â”¬â•‘ de la Independencia 2007', 'Paseo de la Independencia de Zaragoza, con sus seis carriles viarios, tras la remodelaciâ”œâ”‚n de 2002 y antes de la de 2011, esta â”œâ•‘ltima para el paso del tranvâ”œÂ¡a. Al fondo, la plaza de Aragâ”œâ”‚n. Fuente: Wikipedia, 2007.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.65113900, -0.88188300, '0101000020E61000006EBF7CB26238ECBF3813D38558D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15012100399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15012100399.webp', 'https://www.flickr.com/photos/zaragozaantigua/15012100399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
