INSERT INTO public.photos VALUES (23158, 'Convento de San Francisco 2007', 'Contrafuertes del Salâ”œâ”‚n de Quintas del convento de San Francisco, durante las obras de ampliaciâ”œâ”‚n de la Diputaciâ”œâ”‚n Provincial (2007-2011). Este convento, fundado en 1219, fue muy daâ”œâ–’ado en el Sitio de 1809. En 1843 se construyâ”œâ”‚ sobre su solar el palacio de la Diputaciâ”œâ”‚n. La imagen muestra el acceso desde la calle del Cinco de Marzo 8 (al fondo, fuera de plano). Fuente visual: Heraldo de Aragâ”œâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.65194800, -0.88226600, '0101000020E610000074ED0BE8853BECBFA758350873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32474943101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32474943101.webp', 'https://www.flickr.com/photos/zaragozaantigua/32474943101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
