INSERT INTO public.photos VALUES (23296, 'Calle de Alfonso I c.1895', 'Imagen del arranque de la calle Alfonso I capturada desde cierta altura de lo que fuera el antiguo palacio del marquâ”œÂ®s de Campo Franco, situado en el Coso Alto entre el palacio de Sâ”œÃ­stago, y el de Fuentes. A la izquierda, imagen parcial de la antigua casa solariega de los marqueses de Tosos en la ciudad, desde su establecimiento en ella a mediados del siglo XVII, en lo que entonces era la esquina del Coso con el Trenque del Arzobispo, y hasta 1833, en que fue vendida a un particular como nâ”¬â•‘ 7 del Coso. Reformada varias veces, cuando en la dâ”œÂ®cada de los 60 fue abierta la calle Alfonso I, este edificio mantuvo su alineamiento original, hasta que en 1902 fue remodelado profundamente, ya como nâ”¬â•‘ 17 del Coso: realineado, se levantâ”œâ”‚ una nueva planta, se homologaron las alturas de sus bajos a las de los comercios que caracterizaban la calle, se le achaflanâ”œâ”‚ la esquina, y se le dio un estilo mâ”œÃ­s profusamente decorativo, con balconadas y rejerâ”œÂ¡as mâ”œÃ­s "modernas". En la imagen, la antigua casona conserva su esquina en â”œÃ­ngulo y un estilo mâ”œÃ­s austero de mediados del XIX, donde en sus bajos destaca la prestigiosa tienda de sombreros de Gaspar Lamarque. Al otro lado de la calle de Alfonso I, inmueble construido expresamente tras la apertura de la calle para el confitero Eusebio Molins, que en sus bajos habilitâ”œâ”‚ una confiterâ”œÂ¡a, con el caracterâ”œÂ¡stico chaflâ”œÃ­n de los edificios de la burguesa calle, donde se destaca la publicidad de la golosa fâ”œÃ­brica "La Gemela del Buen Gusto", sita junto a la antigua carretera de Valencia. Este edificio tambiâ”œÂ®n fue remodelado en 1902, con proyecto de Fernando de Yarza, dejâ”œÃ­ndole su actual aspecto modernista. Aunque esta imagen viene datada en varias fuentes como de "Jarke", Câ”œÂ®sar Gracia Jarque naciâ”œâ”‚ en 1905, y su actividad como fotâ”œâ”‚grafo, iniciador de la saga "Jarke", comienza al final de la segunda dâ”œÂ®cada del siglo XX. La captura posiblemnete tiene como autor a Anselmo Marâ”œÂ¡a Coyne, o tal vez Ignacio.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65309200, -0.88215500, '0101000020E61000009817601F9D3AECBFBEA3C68498D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22739744680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22739744680.webp', 'https://www.flickr.com/photos/zaragozaantigua/22739744680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
